import{_ as t,o as r,c as a,ag as i}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Frequently asked questions","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":1777988338000}'),o={name:"faq.md"};function s(n,e,c,d,l,h){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="frequently-asked-questions" tabindex="-1">Frequently asked questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently asked questions&quot;">​</a></h1><p>A reference for questions that arrive often enough to deserve a written answer. Short-form Q&amp;A surface; long-form reference lives under <code>/reference</code>.</p><hr><h2 id="what-happens-when-my-qes-expires" tabindex="-1">What happens when my QES expires? <a class="header-anchor" href="#what-happens-when-my-qes-expires" aria-label="Permalink to &quot;What happens when my QES expires?&quot;">​</a></h2><p>Every qualified electronic signature carries a <code>notAfter</code> date — the issuing trust service provider&#39;s cap on how long the certificate is valid. EU QTSPs typically issue qualified certificates with a one-to-three-year validity. When that date passes, the certificate is no longer accepted by Adobe Reader, eIDAS-aware verifiers, or — relevantly here — the <code>zkqes</code> registration flow.</p><p>What this means in practice depends on whether you are looking backward at an already-registered binding, or forward at a new registration.</p><h3 id="already-registered-before-expiry" tabindex="-1">Already registered before expiry <a class="header-anchor" href="#already-registered-before-expiry" aria-label="Permalink to &quot;Already registered before expiry&quot;">​</a></h3><p>Your existing binding remains valid. The on-chain registry recorded that a <code>zkqes</code> proof was verified at the moment of registration, when your certificate was within its <code>notBefore</code> and <code>notAfter</code> window. Once the registry has accepted the proof, no later certificate event — expiry, revocation, key rotation — invalidates the recorded nullifier or the citizen certificate you minted from it.</p><p>This is by design. Registration is a permanent statement that, at registration time, you held a valid qualified signature from an authorised intermediate of your country&#39;s trust list. It is not a continuous attestation. The chain does not poll the QTSP&#39;s revocation list and does not re-check <code>notAfter</code>. Once registered, you are registered.</p><h3 id="registering-after-expiry" tabindex="-1">Registering after expiry <a class="header-anchor" href="#registering-after-expiry" aria-label="Permalink to &quot;Registering after expiry&quot;">​</a></h3><p>You cannot register with an expired certificate. The circuit&#39;s binding parser checks <code>notAfter</code> against the registration timestamp; an expired certificate fails the proof. Equivalently, the trust-list Merkle gate on chain only accepts intermediates whose currently-valid certificates anchor to a published QTSP — if your leaf certificate is past <code>notAfter</code>, no proof generated from it will satisfy the gate.</p><p>The remedy is the same remedy any holder of an expired qualified certificate makes: renew through your QTSP. The renewal flow is QTSP-specific and outside <code>zkqes</code>&#39;s control.</p><h3 id="renewal-flows-by-qtsp" tabindex="-1">Renewal flows by QTSP <a class="header-anchor" href="#renewal-flows-by-qtsp" aria-label="Permalink to &quot;Renewal flows by QTSP&quot;">​</a></h3><ul><li><p><strong>Ukraine — Diia.</strong> Open the Diia mobile app, navigate to the electronic identity entry, and follow the renewal prompt. The renewed certificate is issued under the same <code>subject.serialNumber</code> (your tax identifier), so the wallet-bound nullifier you would derive from a renewed certificate collides with your prior registration. The intended path after renewal is to keep the existing wallet binding, not to register again.</p></li><li><p><strong>Other EU/EEA QTSPs.</strong> Each member state&#39;s qualified trust service providers operate their own renewal channels; consult your QTSP&#39;s documentation directly. The facade-level fact remains constant across the eIDAS perimeter: a renewed certificate produces a fresh <code>notBefore</code>/<code>notAfter</code> window, but the same <code>subject.serialNumber</code>, so <code>zkqes</code>&#39;s nullifier derivation is stable across renewals.</p></li></ul><h3 id="edge-cases" tabindex="-1">Edge cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge cases&quot;">​</a></h3><ul><li><p><strong>Wallet rotation across an expiry boundary.</strong> If you registered with a then-valid certificate and the certificate has since expired, the <code>/account/rotate</code> flow is unavailable until you renew — rotation requires a fresh proof from a currently-valid certificate. This is a deliberate constraint: rotation re-anchors the binding to a new wallet, and re-anchoring requires a fresh signed statement.</p></li><li><p><strong>Lost certificate.</strong> If you lose access to your QES — forgotten credentials, lost device — before renewing, your existing binding remains valid on chain but you cannot rotate. Recovery is QTSP-specific; for Diia, see the official &quot;Втрата доступу&quot; (loss of access) flow.</p></li><li><p><strong>Revoked certificate.</strong> Revocation behaves the same as expiry for <code>zkqes</code>&#39;s purposes. Prior registrations stand; new registrations and rotations fail until a fresh certificate is issued.</p></li></ul>',16)])])}const p=t(o,[["render",s]]);export{u as __pageData,p as default};
